// MARK: - Testbed Server

///  Testbed service for conformance testing.
///
///  Combines simple RPC, channeling, and complex type methods for comprehensive testing.
public protocol TestbedHandler: Sendable {
  ///  Echoes the message back.
  func echo(message: String) async throws -> String
  ///  Returns the message reversed.
  func reverse(message: String) async throws -> String
  ///  Divides two numbers, returning an error if divisor is zero or would overflow.
  func divide(dividend: Int64, divisor: Int64) async throws -> Result<Int64, MathError>
  ///  Looks up a user by ID.
  ///
  ///  - IDs 1..=3: return Ok(Person)
  ///  - IDs 100..=199: return Err(AccessDenied)
  ///  - Anything else: return Err(NotFound)
  func lookup(id: UInt32) async throws -> Result<Person, LookupError>
  ///  Client sends numbers, server returns their sum.
  ///
  ///  Tests: client→server streaming. Server receives via `Rx<T>`, returns scalar.
  func sum(numbers: Rx<Int32>) async throws -> Int64
  ///  Server streams numbers back to client.
  ///
  ///  Tests: server→client streaming. Server sends via `Tx<T>`.
  func generate(count: UInt32, output: Tx<Int32>) async throws
  ///  Server streams numbers back to client on a non-idempotent retry probe.
  ///
  ///  Tests: channel retry fails closed when the session breaks mid-stream.
  func generateRetryNonIdem(count: UInt32, output: Tx<Int32>) async throws
  ///  Server streams numbers back to client on an idempotent retry probe.
  ///
  ///  Tests: channel retry reruns the method with fresh channel bindings.
  func generateRetryIdem(count: UInt32, output: Tx<Int32>) async throws
  ///  Bidirectional: client sends strings, server echoes each back.
  ///
  ///  Tests: bidirectional streaming. Server receives via `Rx<T>`, sends via `Tx<T>`.
  func transform(input: Rx<String>, output: Tx<String>) async throws
  ///  Echo a point back.
  func echoPoint(point: Point) async throws -> Point
  ///  Create a person and return it.
  func createPerson(name: String, age: UInt8, email: String?) async throws -> Person
  ///  Calculate the area of a rectangle.
  func rectangleArea(rect: Rectangle) async throws -> Double
  ///  Get a color by name.
  func parseColor(name: String) async throws -> Color?
  ///  Calculate the area of a shape.
  func shapeArea(shape: Shape) async throws -> Double
  ///  Create a canvas with given shapes.
  func createCanvas(name: String, shapes: [Shape], background: Color) async throws -> Canvas
  ///  Echo a deeply nested payload back unchanged.
  func echoGnarly(payload: GnarlyPayload) async throws -> GnarlyPayload
  ///  Process a message and return a response.
  func processMessage(msg: Message) async throws -> Message
  ///  Return multiple points.
  func getPoints(count: UInt32) async throws -> [Point]
  ///  Test tuple types.
  func swapPair(pair: (Int32, String)) async throws -> (String, Int32)
  ///  Echo raw bytes back. Tests Vec<u8> as a first-class arg/return type.
  func echoBytes(data: Data) async throws -> Data
  ///  Echo a bool. Tests the bool primitive type.
  func echoBool(b: Bool) async throws -> Bool
  ///  Echo a u64. Tests the u64 primitive type.
  func echoU64(n: UInt64) async throws -> UInt64
  ///  Echo an optional string. Tests Option<String> directly.
  func echoOptionString(s: String?) async throws -> String?
  ///  Sum a large stream (tests channel credit/backpressure for > initial credit).
  ///
  ///  Tests: channel flow control when sender must wait for credit grants.
  func sumLarge(numbers: Rx<Int32>) async throws -> Int64
  ///  Generate a large stream (tests Tx backpressure with > initial credit items).
  ///
  ///  Tests: server must wait for client to grant credit mid-stream.
  func generateLarge(count: UInt32, output: Tx<Int32>) async throws
  ///  Return all three Color variants in a Vec, testing enum + vec round-trip.
  func allColors() async throws -> [Color]
  ///  Accept multiple args of different types; return a summary struct.
  ///  Tests multi-arg encoding and struct return.
  func describePoint(label: String, x: Int32, y: Int32, active: Bool) async throws -> TaggedPoint
  ///  Echo a nested enum back unchanged. Tests deep enum encoding.
  func echoShape(shape: Shape) async throws -> Shape
  ///  Echo a status back. Tests simple enum with unit variants.
  func echoStatusV1(status: Status) async throws -> Status
  ///  Echo a tag back. Tests struct with String + u32 + String fields.
  func echoTagV1(tag: Tag) async throws -> Tag
  ///  Echo a profile back. Tests added optional field.
  func echoProfile(profile: Profile) async throws -> Profile
  ///  Echo a record back. Tests field reordering.
  func echoRecord(record: Record) async throws -> Record
  ///  Echo a status back. Tests added enum variant.
  func echoStatus(status: Status) async throws -> Status
  ///  Echo a tag back. Tests removed field (v2 drops a field v1 has).
  func echoTag(tag: Tag) async throws -> Tag
  ///  Echo a measurement back. Tests incompatible type change.
  func echoMeasurement(m: Measurement) async throws -> Measurement
  ///  Echo a config back. Tests missing required field.
  func echoConfig(c: Config) async throws -> Config
}

public final class TestbedDispatcher: ServiceDispatcher {
  private let handler: TestbedHandler
  private let schemaRegistry: [UInt64: Schema]
  private let methodSchemas: [UInt64: MethodSchemaInfo]

  public init(
    handler: TestbedHandler, schemaRegistry: [UInt64: Schema] = testbed_schema_registry,
    methodSchemas: [UInt64: MethodSchemaInfo] = testbed_method_schemas
  ) {
    self.handler = handler
    self.schemaRegistry = schemaRegistry
    self.methodSchemas = methodSchemas
  }

  public func dispatch(
    methodId: UInt64, payload: [UInt8], requestId: UInt64, registry: ChannelRegistry,
    schemaSendTracker _: SchemaSendTracker, taskTx: @escaping @Sendable (TaskMessage) -> Void
